import anthropic

client = anthropic.Anthropic()

def add_context_cached(chunk_text: str, whole_doc: str) -> str:
    """Use Anthropic prompt caching to amortise the whole-doc cost."""
    response = client.beta.prompt_caching.messages.create(
        model="claude-3-haiku-20240307",
        max_tokens=200,
        system=[
            {
                "type": "text",
                "text": "You situate document chunks within their source document.",
                # Whole document text — cached after first call for this document
                "cache_control": {"type": "ephemeral"}
            }
        ],
        messages=[{
            "role": "user",
            "content": (
                f"<document>\n{whole_doc}\n</document>\n"
                f"Chunk: <chunk>\n{chunk_text}\n</chunk>\n"
                "Write 1-2 sentences of context. No preamble."
            )
        }]
    )
    context = response.content[0].text.strip()
    return f"{context}\n\n{chunk_text}"

import hashlib, redis, json

r = redis.Redis(host="localhost", port=6379, db=0)

def get_or_generate_context(doc_id: str, chunk_idx: int, chunk_text: str, whole_doc: str) -> str:
    key = hashlib.sha256(f"{doc_id}:{chunk_idx}:{chunk_text}".encode()).hexdigest()
    cached = r.get(f"ctx:{key}")
    if cached:
        return cached.decode()
    context = add_context(chunk_text, whole_doc)  # LLM call
    r.setex(f"ctx:{key}", 86400 * 30, context)   # 30-day TTL
    return context

def build_contextual_index(doc_id: str, document_text: str, chunks: list[str]):
    contextual_docs = []
    for i, chunk in enumerate(chunks):
        ctx_chunk = get_or_generate_context(doc_id, i, chunk, document_text)
        contextual_docs.append(Document(page_content=ctx_chunk, metadata={"doc_id": doc_id, "chunk_idx": i}))
    return contextual_docs
